Let $g(x) = \frac{f(x)}{f(x) + 1}$ for all real numbers $x$ where $f(x) \neq -1$. Which of the graphs below is the graph of $y = g(x)$? Assume $f$ is the function whose graph is shown above. 
(Note: The graph above means the original graph in the original problem.)

Your response should start after this graph.


[asy]
unitsize(0.5 cm);

picture[] graf;
int i, n;

real func(real x) {
  real y;
  if (x >= -3 && x <= 0) {y = -2 - x;}
  if (x >= 0 && x <= 2) {y = sqrt(4 - (x - 2)^2) - 2;}
  if (x >= 2 && x <= 3) {y = 2*(x - 2);}
  return(y);
}

real funcb(real x) {
  real y = min(-1,func(x))/(func(x) + 1);
  return(y);
}

real funcc(real x) {
  real y = func(x)/(func(x) + 1);
  return(y);
}

real funcd(real x) {
  real y = func(x)/(func(x) + 2);
  return(y);
}

real funce(real x) {
  real y = func(x)/(func(x) + 3);
  return(y);
}

real funcf(real x) {
  real y = func(x)/(func(x) - 1);
  return(y);
}

